// Create a test file that uses onResponse callback
const codeceptConfig = `
exports.config = {
  tests: './test_api_*.js',
  output: './output',
  helpers: {
    REST: {
      endpoint: 'https://jsonplaceholder.typicode.com',
      onRequest: (request) => {
        console.log('onRequest called');
        request.headers['start-time'] = new Date().getTime();
      },
      onResponse: (response) => {
        console.log('onResponse called');
        const startTime = response.config.headers['start-time'];
        const endTime = new Date().getTime();
        const responseTime = endTime - startTime;
        response.headers['x-response-time'] = responseTime;
      },
    },
    JSONResponse: {}
  }
}
`;

const testFile = `
Feature('API Test');

Scenario('test onResponse callback', async ({ I }) => {
  const response = await I.sendGetRequest('/posts/1');
  console.log('Response headers:', JSON.stringify(response.headers));

  // The onResponse callback should have added x-response-time header
  if (response.headers['x-response-time']) {
    console.log('SUCCESS: x-response-time header found:', response.headers['x-response-time']);
  } else {
    console.log('FAILURE: x-response-time header NOT found');
    throw new Error('onResponse callback was not executed - x-response-time header missing');
  }
});
`;

const fs = require('fs');
const testDir = '/tmp/codecept_test_onresponse';

// Clean up and create test directory
if (fs.existsSync(testDir)) {
  fs.rmSync(testDir, { recursive: true });
}
fs.mkdirSync(testDir, { recursive: true });

// Write test files
fs.writeFileSync(path.join(testDir, 'codecept.conf.js'), codeceptConfig);
fs.writeFileSync(path.join(testDir, 'test_api_basic.js'), testFile);

console.log('Test files created in:', testDir);
console.log('\n=== Running test to reproduce the bug ===\n');

// Run the test
exec(`cd ${testDir} && npx codeceptjs run --verbose`, (error, stdout, stderr) => {
  console.log(stdout);
  if (stderr) console.log('STDERR:', stderr);

  if (stdout.includes('SUCCESS: x-response-time header found')) {
    console.log('\n✓ Test PASSED - onResponse callback is working correctly');
  } else if (stdout.includes('FAILURE: x-response-time header NOT found') || error) {
    console.log('\n✗ Test FAILED - onResponse callback is NOT working (bug reproduced)');
  }

  // Clean up
  fs.rmSync(testDir, { recursive: true });
});

