const assert = require('assert');
const path = require('path');
const exec = require('child_process').exec;

// Create a custom helper that checks the response
const customHelper = `
const Helper = require('@codeceptjs/helper');

class CustomHelper extends Helper {
  async checkResponseTime() {
    const response = this.helpers.JSONResponse.response;
    console.log('\\n=== Custom Helper Check ===');
    console.log('Response headers:', JSON.stringify(response.headers));

    if (response.headers['x-response-time']) {
      console.log('SUCCESS: x-response-time header found:', response.headers['x-response-time'], 'ms');
    } else {
      console.log('FAILURE: x-response-time header NOT found in response');
      throw new Error('onResponse callback was not executed properly - x-response-time header missing');
    }
  }
}

module.exports = CustomHelper;
`;

const codeceptConfig = `
exports.config = {
  tests: './test_jsonresponse_*.js',
  output: './output',
  helpers: {
    REST: {
      endpoint: 'https://jsonplaceholder.typicode.com',
      onRequest: (request) => {
        console.log('\\n>>> onRequest callback executed');
        request.headers['start-time'] = new Date().getTime();
      },
      onResponse: (response) => {
        console.log('>>> onResponse callback executed');
        const startTime = response.config.headers['start-time'];
        if (startTime) {
          const endTime = new Date().getTime();
          const responseTime = endTime - startTime;
          response.headers['x-response-time'] = responseTime;
          console.log('>>> Set x-response-time:', responseTime, 'ms');
        } else {
          console.log('>>> ERROR: start-time not found in request headers');
        }
      },
    },
    JSONResponse: {},
    CustomHelper: {
      require: './custom_helper.js'
    }
  }
}
`;

const testFile = `
Feature('API Test with JSONResponse');

Scenario('test onResponse callback with JSONResponse helper', async ({ I }) => {
  // Make a request
  await I.sendGetRequest('/posts/1');

  // Check response using JSONResponse helper
  I.seeResponseCodeIsSuccessful();

  // Use custom helper to check response time header
  await I.checkResponseTime();
});
`;

const fs = require('fs');
const testDir = '/tmp/codecept_test_jsonresponse';

// Clean up and create test directory
if (fs.existsSync(testDir)) {
  fs.rmSync(testDir, { recursive: true });
}
fs.mkdirSync(testDir, { recursive: true });

// Write test files
fs.writeFileSync(path.join(testDir, 'codecept.conf.js'), codeceptConfig);
fs.writeFileSync(path.join(testDir, 'custom_helper.js'), customHelper);
fs.writeFileSync(path.join(testDir, 'test_jsonresponse_api.js'), testFile);

console.log('Test files created in:', testDir);
console.log('\n=== Running test with JSONResponse helper to check if user onResponse is called ===\n');

// Run the test
exec(`cd ${testDir} && npx codeceptjs run --verbose`, (error, stdout, stderr) => {
  console.log(stdout);
  if (stderr) console.log('STDERR (warnings):', stderr.substring(0, 500));

  if (stdout.includes('SUCCESS: x-response-time header found')) {
    console.log('\n✓ Test PASSED - User onResponse callback is working correctly');
  } else if (stdout.includes('FAILURE: x-response-time header NOT found') || error) {
    console.log('\n✗ Test FAILED - User onResponse callback is NOT working (bug confirmed)');
    console.log('This means JSONResponse helper is overwriting the user onResponse callback');
  }

  // Clean up
