const path = require('path');
const assert = require('assert');
const REST = require('../../lib/helper/REST');
const JSONResponse = require('../../lib/helper/JSONResponse');
const container = require('../../lib/container');

describe('REST Helper onResponse callback', () => {
  before(() => {
    global.codeceptjs = require('../../lib');
  });

  beforeEach(() => {
    container.clear();
  });

  it('should call user-defined onResponse callback when JSONResponse helper is not present', async () => {
    let onResponseCalled = false;

    const restConfig = {
      endpoint: 'https://jsonplaceholder.typicode.com',
      onResponse: (response) => {
        onResponseCalled = true;
        response.headers['x-custom'] = 'test-value';
      },
    };

    const rest = new REST(restConfig);
    rest.helpers = {};

    const response = await rest.sendGetRequest('/posts/1');

    assert.strictEqual(onResponseCalled, true, 'User onResponse callback should be called');
    assert.strictEqual(response.headers['x-custom'], 'test-value', 'Response should have custom header');
  });

  it('should preserve user-defined onResponse callback when JSONResponse helper is present', async () => {
    let userOnResponseCalled = false;

    const restConfig = {
      endpoint: 'https://jsonplaceholder.typicode.com',
      onResponse: (response) => {
        userOnResponseCalled = true;
        response.headers['x-response-time'] = 100;
      },
    };

    const rest = new REST(restConfig);
    const jsonResponse = new JSONResponse({});

    // Simulate the helpers container
    rest.helpers = { REST: rest, JSONResponse: jsonResponse };
    jsonResponse.helpers = { REST: rest, JSONResponse: jsonResponse };

    // Initialize JSONResponse (this is where it overrides onResponse)
    jsonResponse._beforeSuite();

    // Make a request
    const response = await rest.sendGetRequest('/posts/1');

    // Check if user callback was called
    assert.strictEqual(userOnResponseCalled, true, 'User onResponse callback should be called even with JSONResponse helper');
    assert.strictEqual(response.headers['x-response-time'], 100, 'Response should have user-defined header');

    // Check if JSONResponse also got the response
    assert.notStrictEqual(jsonResponse.response, null, 'JSONResponse should have captured the response');
    assert.strictEqual(jsonResponse.response.status, response.status, 'JSONResponse should have the same response');
  });
});

