const path = require('path');
const exec = require('child_process').exec;
const fs = require('fs');

const codeceptConfig = `
exports.config = {
  tests: './test_final_*.js',
  output: './output',
  helpers: {
    REST: {
      endpoint: 'https://jsonplaceholder.typicode.com',
      onRequest: (request) => {
        console.log('>>> onRequest callback executed');
        request.headers['start-time'] = new Date().getTime();
      },
      onResponse: (response) => {
        console.log('>>> onResponse callback executed');
        const startTime = response.config.headers['start-time'];
        if (startTime) {
          const endTime = new Date().getTime();
          const responseTime = endTime - startTime;
          response.headers['x-response-time'] = responseTime;
          console.log('>>> Set x-response-time:', responseTime, 'ms');
        }
      },
    },
    JSONResponse: {},
  }
}
`;

const testFile = `
Feature('API Test');

Scenario('test onResponse callback with JSONResponse', async ({ I }) => {
  await I.sendGetRequest('/posts/1');
  I.seeResponseCodeIsSuccessful();
  console.log('Test completed successfully!');
});
`;

const testDir = '/tmp/codecept_final_test';

// Clean up and create test directory
if (fs.existsSync(testDir)) {
  fs.rmSync(testDir, { recursive: true });
}
fs.mkdirSync(testDir, { recursive: true });

// Write test files
fs.writeFileSync(path.join(testDir, 'codecept.conf.js'), codeceptConfig);
fs.writeFileSync(path.join(testDir, 'test_final_check.js'), testFile);

console.log('=== Running final integration test ===\n');

// Run the test
exec(`cd ${testDir} && npx codeceptjs run --verbose`, (error, stdout, stderr) => {
  console.log(stdout);

  if (stdout.includes('>>> onRequest callback executed') &&
      stdout.includes('>>> onResponse callback executed') &&
      stdout.includes('>>> Set x-response-time:') &&
      stdout.includes('OK  | 1 passed')) {
    console.log('\n✓✓✓ SUCCESS: The bug is fixed! Both onRequest and onResponse callbacks are working correctly with JSONResponse helper ✓✓✓');
  } else if (!stdout.includes('>>> onResponse callback executed')) {
    console.log('\n✗✗✗ FAILURE: onResponse callback is still not being called ✗✗✗');
  } else if (error) {
    console.log('\n✗✗✗ TEST FAILED ✗✗✗');
  }

  // Clean up
  fs.rmSync(testDir, { recursive: true });
});

